interface User {
  id: string
  name: string
  role: 'student' | 'ngo' | 'admin'
  hours: number
  email: string
  avatar: string
  joinDate: string
  badges: Badge[]
  userBadges?: Badge[]
  completedMissions: number
  organizationsHelped: number
  rating: number
}

interface Badge {
  id: string
  name: string
  icon: string
  earnedDate: string
  company: string
}

interface Mission {
  id: number
  title: string
  description: string
  location: string
  date: string
  startTime?: string
  endTime?: string
  hours: number
  participants: string
  maxParticipants: number
  currentParticipants: number
  category: string
  difficulty: 'Easy' | 'Medium' | 'Hard'
  organizer: string
  organizerId?: string  // ID of the NGO user who created the mission
  image: string
  imageUrl?: string
  joined: boolean
  region?: string
  country?: string
  language?: string
  report?: {
    text: string
    photos: string[]
    submittedAt: string
  }
}

interface CertProgram {
  id: string
  ngoId: string
  ngoName: string
  ngoLogo: string
  programName: string
  requiredHours: number
  isActive: boolean
  createdAt: string
}

interface CertRequest {
  id: string
  userId: string
  userName: string
  ngoId: string
  ngoName: string
  programId: string
  programName: string
  hoursWithNgo: number
  status: 'pending' | 'approved' | 'rejected'
  requestedAt: string
  approvedAt?: string
}

// Scroll animation hook — triggers once when element enters viewport
function useScrollAnimation(threshold = 0.15) {
  const ref = useRef<HTMLDivElement>(null)
  const [isVisible, setIsVisible] = useState(false)

  useEffect(() => {
    const element = ref.current
    if (!element) return

    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting) {
          setIsVisible(true)
          observer.unobserve(element)
        }
      },
      { threshold }
    )

    observer.observe(element)
    return () => observer.disconnect()
  }, [threshold])

  return { ref, isVisible }
}

// Animated wrapper for landing page sections
function AnimatedSection({ children, delay = 0, className = '', style: extraStyle }: {
  children: React.ReactNode
  delay?: number
  className?: string
  style?: React.CSSProperties
}) {
  const { ref, isVisible } = useScrollAnimation(0.1)

  return (
    <div
      ref={ref}
      className={className}
      style={{
        opacity: isVisible ? 1 : 0,
        transform: isVisible ? 'translateY(0)' : 'translateY(40px)',
        transition: `opacity 0.8s cubic-bezier(0.4, 0, 0.2, 1) ${delay}s, transform 0.8s cubic-bezier(0.4, 0, 0.2, 1) ${delay}s`,
        ...extraStyle,
      }}
    >
      {children}
    </div>
  )
}

// Count-up animation component for stat numbers
function CountUp({ end, suffix = '', duration = 2000 }: {
  end: number
  suffix?: string
  duration?: number
}) {
  const { ref, isVisible } = useScrollAnimation(0.3)
  const [count, setCount] = useState(0)

  useEffect(() => {
    if (!isVisible) return

    let startTime: number | null = null
    const animate = (timestamp: number) => {
      if (!startTime) startTime = timestamp
      const progress = Math.min((timestamp - startTime) / duration, 1)
      const eased = 1 - Math.pow(1 - progress, 3) // ease-out cubic
      setCount(Math.floor(eased * end))
      if (progress < 1) requestAnimationFrame(animate)
    }
    requestAnimationFrame(animate)
  }, [isVisible, end, duration])

  return <span ref={ref}>{count.toLocaleString()}{suffix}</span>
}


