  useEffect(() => {
    if (currentPage === 'landing') {
      const interval = setInterval(() => {
        setCurrentSlide((prev) => (prev + 1) % heroImages.length)
      }, 6000)
      return () => clearInterval(interval)
    }
  }, [currentPage])

  // Inject theme CSS variables into document whenever theme changes
  useEffect(() => {
    const vars = themes[userTheme]?.vars || themes.violet.vars
    let styleEl = document.getElementById('kw-theme') as HTMLStyleElement | null
    if (!styleEl) {
      styleEl = document.createElement('style')
      styleEl.id = 'kw-theme'
      document.head.appendChild(styleEl)
    }
    styleEl.textContent = `:root { ${Object.entries(vars).map(([k, v]) => `${k}: ${v}`).join('; ')} } body { background: var(--tpbg); transition: background 0.4s ease; }`
    localStorage.setItem('kindworld_user_theme', userTheme)
  }, [userTheme])

