  const getMonthBuckets = (count: number) => {
    const now = new Date()
    return Array.from({ length: count }, (_, i) => {
      const d = new Date(now.getFullYear(), now.getMonth() - (count - 1 - i), 1)
      return { year: d.getFullYear(), month: d.getMonth(), label: d.toLocaleString('en', { month: 'short', year: 'numeric' }), short: d.toLocaleString('en', { month: 'short' }) }
    })
  }

  const buildMonthlyChart = (buckets: { year: number; month: number; label: string; short: string }[]) =>
    buckets.map(b => {
      const subs = userApprovedSubs.filter((s: any) => {
        const d = new Date(s.submittedAt)
        return d.getFullYear() === b.year && d.getMonth() === b.month
      })
      return {
        month: b.label, shortMonth: b.short,
        hours: subs.reduce((sum: number, s: any) => sum + (s.hoursSubmitted || s.hours || 0), 0),
        missions: subs.map((s: any) => ({ name: s.missionTitle || '', hours: s.hoursSubmitted || s.hours || 0, date: (s.submittedAt || '').split('T')[0] })),
        totalMissions: subs.length,
        organizations: [...new Set(subs.map((s: any) => s.organizerId || ''))]
      }
    })

  const getChartData = () => {
    switch (chartTimePeriod) {
      case 'year': return buildMonthlyChart(getMonthBuckets(12))
      case 'allTime': {
        const yearTotals: Record<number, number> = {}
        userApprovedSubs.forEach((s: any) => {
          const y = new Date(s.submittedAt).getFullYear()
          yearTotals[y] = (yearTotals[y] || 0) + (s.hoursSubmitted || s.hours || 0)
        })
        const cy = new Date().getFullYear()
        return [cy - 3, cy - 2, cy - 1, cy].map(y => ({ month: String(y), shortMonth: String(y), hours: yearTotals[y] || 0, missions: [], totalMissions: 0, organizations: [] }))
      }
      default: return buildMonthlyChart(getMonthBuckets(6))
    }
  }

